// T606 TenantConfigurationManager — immutable machine key guard

// Compile-time constant — immutable at runtime, no FREEDOM override
const MACHINE_LOCKED_KEYS = new Set([
  'system.fabric.router',
  'security.occ.enabled',
  'system.tenant.isolation.mode',
]) as const;

async updateConfig(key: string, value: unknown): Promise<DataProcessResult<void>> {
  const tenantId = this.tenantContext.getTenantId(); // ALS only

  // ORDER 1: locked key guard — no storage attempt on match
  if (MACHINE_LOCKED_KEYS.has(key)) {
    await this.queue.enqueue('ConfigKeyImmutable', {
      tenantId,
      rejectedKey: key,
      rejectionReason: 'MACHINE_LOCKED_KEY',
      rejectedAt: new Date().toISOString(),
    });
    return DataProcessResult.failure('MACHINE_LOCKED_KEY', `Key ${key} is engine-immutable`);
  }

  // ORDER 2: quota check
  const maxKeys = await this.freedom.getConfig('tenant_config_max_custom_keys'); // F1522
  const existingCount = await this.configStore.countCustomKeys(tenantId); // F1523
  if (existingCount >= maxKeys) {
    return DataProcessResult.failure('QUOTA_EXCEEDED', 'Custom key quota reached');
  }

  // ORDER 3: OCC write
  const { occVersion } = await this.configStore.storeDocument(
    'xiigen-tenant-config',
    { tenantId, configKey: key, value },
    { occ: true }, // F1523 — OCC mandatory
  );

  await this.queue.enqueue('TenantConfigurationUpdated', {
    tenantId, configKey: key, occVersion, updatedAt: new Date().toISOString(),
  });
  return DataProcessResult.success();
}
